	,	list = [];

	for (var i = 0; i < data.purchase.products.length; i++)
	{
		list.push(data.purchase.products[i].id);
	}

	return list;
}

function()
{
	var data = {{SuiteCommerce - Ecommerce}}
	,	list = [];

	for (var i = 0; i < data.purchase.products.length; i++)
	{
		list.push(data.purchase.products[i].sku);
	}

	return list;
}

function() {
  var ecom = {{ecommerce}} || {};

  // Look for items in: 1. GA4 Standard, 2. UA Purchase, 3. UA Add/Remove, 4. UA Detail/ProductView
  var products = ecom.items ||
                 (ecom.purchase && ecom.purchase.products) ||
                 (ecom.add && ecom.add.products) ||
                 (ecom.detail && ecom.detail.products) || [];

  return products.map(function(item) {
    return {
      item_id: item.item_id || item.id || item.sku,
      item_name: item.item_name || item.name,
      price: Number(item.price || 0),
      quantity: item.quantity || 1,
      item_variant: item.variant || "",
      item_category: item.category || ""
    };
  });
}

function() {
  var gtmData = window.google_tag_manager[{{Container ID}}].dataLayer.get('gtm');
  return gtmData.start + '.' + gtmData.uniqueEventId;
}

function() {
  var match = document.cookie.match(/(^|;)\s*_gtm_email=([^;]+)/);
  return match ? decodeURIComponent(match[2]) : undefined;
}

function() {
    var cookieVal, fbclid, fbc;
    // 1. Read _fbc cookie
    try {
          var m = document.cookie.match(/(^|;\s*)_fbc=([^;]+)/);
          if (m) cookieVal = m[2];
    } catch(e) {}
    if (cookieVal) {
          try { localStorage.setItem('_fbc_backup', cookieVal); } catch(e) {}
          return cookieVal;
    }
    // 2. Read localStorage backup
    try {
          var ls = localStorage.getItem('_fbc_backup');
          if (ls) return ls;
    } catch(e) {}
    // 3. Build from fbclid in URL query string
    try {
          var sp = new URLSearchParams(window.location.search);
          fbclid = sp.get('fbclid');
    } catch(e) {}
    // 4. Build from fbclid in URL hash (SuiteCommerce SPA)
    if (!fbclid) {
          try {
                  var hash = window.location.hash;
                  var qi = hash.indexOf('?');
                  if (qi > -1) {
                            var hp = new URLSearchParams(hash.substring(qi));
                            fbclid = hp.get('fbclid');
                  }
          } catch(e) {}
    }
    // 5. Check referrer for fbclid
    if (!fbclid) {
          try {
                  var ref = document.referrer;
                  if (ref && ref.indexOf('fbclid=') > -1) {
                            var ru = new URL(ref);
                            fbclid = ru.searchParams.get('fbclid');
                  }
          } catch(e) {}
    }
    if (fbclid) {
          fbc = 'fb.1.' + Date.now() + '.' + fbclid;
          try {
                  document.cookie = '_fbc=' + fbc + ';max-age=7776000;path=/;domain=.verociousmotorsports.com;SameSite=Lax';
          } catch(e) {}
          try { localStorage.setItem('_fbc_backup', fbc); } catch(e) {}
          return fbc;
    }
    return undefined;
}

function() {
  var match = document.cookie.match(/(^|;)\s*_fbp=([^;]+)/);
  return match ? match[2] : undefined;
}

